features.snippet:
always @ (posedge clk or negedge rst_n) begin
    if (!rst_n)
        cstate <= IDLE;
    else
        cstate <= nstate;
end

case (cstate)
    IDLE: nstate = START;
    START: nstate = ready ? WORKING : START;
    WORKING: nstate = ready ? (stop ? END : WORKING) : WORKING;
    END: nstate = ready ? IDLE : END;
    default: nstate = IDLE;
endcase
